def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 60.0 + np.log1p(cap) * 30
        fluctuation = 0.0
        penalty = 0.0
        bonus = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.2)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 45 * np.cos(cap * 2)
            else:
                base_priority -= 50 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 25 / i
            for q in range(5):
                penalty += np.exp(-usage * (q+1)) * 5 * q**2
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 3000 * delta ** 2 + 250 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 20 / j
            if int(cap * 4) % 4 == 1:
                base_priority += 50 * np.tan(cap / 10)
            for r in range(3):
                penalty += (usage**(r+1)) * 10 / (r+1)
        elif 2.5 < usage <= 4:
            base_priority += 1500 * (usage - 2.5) ** 2.5
            for k in range(1, 15):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 15 / k
                    if k % 4 == 2:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 13 and usage > 3.2:
                        fluctuation += 30
            if cap % 1.7 < 0.4:
                base_priority += 40 * np.sin(cap * 2.5)
            for s in range(1,5):
                bonus += np.log1p(s * cap) * 3
        elif 1.2 < usage <= 2.5:
            base_priority += 1100 * (usage - 1.2) ** 3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 30 / m
                    if m % 4 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 2)
                    if m == 15 and usage > 1.9:
                        fluctuation += 25
            if cap % 1.8 < 0.35:
                base_priority += 35 * np.cos(cap * 2.5)
            for n in range(2, 7):
                penalty += (cap % n) * (20 / n)
        elif 0.6 < usage <= 1.2:
            base_priority += 140 * (1.2 - usage)
            for n in range(1, 12):
                pwr = usage ** n
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / n
                if usage < 0.05 * n:
                    fluctuation -= 7 * n
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.1:
                base_priority += np.log1p(cap * 25) * 45
            else:
                base_priority += (cap % 7) * 25
            for w in range(1, 4):
                bonus += np.sin(cap * w) * 12
        else:
            base_priority += 300 * (1 - usage) ** 2.2
            for o in range(1, 20):
                pwr = usage ** o
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 18 / o
                if usage < 0.01 * o:
                    fluctuation -= 10 * o
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 340
            elif cap < 1.0:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 8) * 35
            for x in range(1, 5):
                penalty += np.cos(cap * x) * 10
        priority = base_priority + fluctuation + bonus - penalty
        if cap < 0.05:
            priority += 90
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.15:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1500) % (s + 5) == 1:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.93:
                priority += 100
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3000) % 17 == 0:
            proximity += 18
        if int(cap * 1000) % 29 == 0:
            proximity -= 12
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 10)
            if diff < 0.015:
                proximity += 22 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 10)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 7)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 9):
                priority -= z * 12
        elif usage > 0.96:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 2.5:
            if cap % 1 < 0.08:
                priority += 45
            if (int(cap * 2700) % 27 == 0) and (usage > 0.75):
                priority += 65
            for bb in range(1, 7):
                if (int(cap * 650) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
